frappe.ui.form.on('Rental Item Template', {

    item_model: function(frm) {

    setItemModelLong(frm);

  },
      item_model_long: function(frm) {

    setItemName(frm);

  },

  item_type: function(frm) {

    setItemName(frm);

  },

  item_brand: function(frm) {

    setItemName(frm);

  }

});

function setItemModelLong(frm) {

  var name = '-';

  if (frm.doc.item_model) {

    name = frm.doc.item_model;

  }

  frm.set_value('item_model_long', name.trim());

}


function setItemName(frm) {

  var name = '';

  if (frm.doc.item_model) {

    name += frm.doc.item_model_long;

  }

  if (frm.doc.item_brand) {

    name += ' ' + frm.doc.item_brand;

  }

  if (frm.doc.item_type) {

    name += ' ' + frm.doc.item_type;

  }

  frm.set_value('item_name', name.trim());

  //console.log('item_name')

}

frappe.ui.form.on("Rental Item Unit", {
    refresh: function(frm) {
        frm.disable_save(); // disables save

        // Hide 'New' button in the list view link
        frm.page.set_secondary_action(null);

        // Hide 'Menu' actions (like 'Rename', 'Print', etc.)
        frm.page.clear_menu();

        // Hide 'Create' in the toolbar (if list view is open)
        if (frm.page.btn_primary) {
            frm.page.btn_primary.hide();
        }
    }
});

frappe.ui.form.on("Rental Item Maintenance", {

    onload(frm) {
        frm.trigger("update_fields_ui");
    },

    refresh(frm) {
        frm.trigger("update_fields_ui");
    },

    workflow_state(frm) {
        frm.trigger("update_fields_ui");
    },

    // -----------------------------
    // UI-only logic
    // -----------------------------
    update_fields_ui(frm) {
        const state = frm.doc.workflow_state;

        // maintained_by hidden unless Attention Required
        frm.toggle_display("maintained_by", state !== "Attention Required");

        // Show maintenance fields on In Repair & Complete
        const show_maintenance_fields =
            state === "In Repair" || state === "Complete";

        frm.toggle_display("maintenance_result", show_maintenance_fields);
        frm.toggle_display("final_condition", show_maintenance_fields);

        // unit_condition always visible
        frm.toggle_display("unit_condition", true);

        // issue_description MUST always be visible
        frm.toggle_display("issue_description", true);

        // prevent Frappe from auto-hiding read-only empty fields
        frm.set_df_property("issue_description", "hidden", false);

        // issue_description read-only ONLY on Complete
        frm.set_df_property(
            "issue_description",
            "read_only",
            state === "Complete"
        );
    },

    // -----------------------------
    // Data cleanup before save
    // -----------------------------
    before_save(frm) {
        const state = frm.doc.workflow_state;

        if (state === "Attention Required") {
            frm.doc.maintained_by = null;
            frm.doc.final_condition = null;
            frm.doc.maintenance_result = null;
        }
        else if (state === "In Repair") {
            frm.doc.unit_condition = null;
        }
        else if (state === "Complete") {
            frm.doc.unit_condition = null;
        }
    }

});

frappe.ui.form.on("Rental Item Maintenance", {
    before_workflow_action(frm) {
        if (frm.is_new()) {
            return frm.save();
        }
    }
});

frappe.ui.form.on('Rental Item Unit', {
    refresh(frm) {
        update_location_code(frm);
    },
    zone: update_location_code,
    aisle: update_location_code,
    section: update_location_code,
    level: update_location_code,
    position: update_location_code
});

function update_location_code(frm) {
    let parts = [];

    if (frm.doc.zone) parts.push(frm.doc.zone);
    if (frm.doc.aisle) parts.push(frm.doc.aisle);
    if (frm.doc.section) parts.push(frm.doc.section);
    if (frm.doc.level) parts.push(frm.doc.level);
    if (frm.doc.position) parts.push(frm.doc.position);

    let location = parts.join('-');

    // If empty, show placeholder
    if (!location) location = '-';

    frm.set_value('location_code', location);
}

frappe.ui.form.on('Rental Item Unit', {
    refresh(frm) {
        if (frm.doc.unit_type === 'Box' && frm.doc.item_unit_list && frm.doc.item_unit_list.length > 0) {
            
            // 1️⃣ Batch fetch conditions to avoid multiple DB hits
            const document_ids = frm.doc.item_unit_list.map(row => row.document_id).filter(Boolean);
            
            if (document_ids.length > 0) {
                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Rental Item Unit',
                        filters: [['name', 'in', document_ids]],
                        fields: ['name', 'unit_condition']
                    },
                    callback: function(r) {
                        if (r.message) {
                            // Create a map for quick lookup
                            const condition_map = {};
                            r.message.forEach(d => { condition_map[d.name] = d.unit_condition; });

                            // Update child rows in memory
                            frm.doc.item_unit_list.forEach(row => {
                                let latest_cond = condition_map[row.document_id];
                                if (latest_cond && row.unit_condition !== latest_cond) {
                                    frappe.model.set_value(row.doctype, row.name, 'unit_condition', latest_cond);
                                }
                            });
                            
                            // 2️⃣ Update parent condition after child sync
                            update_box_unit_condition(frm);
                        }
                    }
                });
            }
        }
    },

    // Trigger when items are added or removed
    item_unit_list_add(frm) {
        if (frm.doc.unit_type === 'Box') update_box_unit_condition(frm);
    },
    item_unit_list_remove(frm) {
        if (frm.doc.unit_type === 'Box') update_box_unit_condition(frm);
    }
});

// Trigger when the child table field itself is edited manually
frappe.ui.form.on('Box Item Unit Child Table', {
    unit_condition(frm) {
        if (frm.doc.unit_type === 'Box') {
            update_box_unit_condition(frm);
        }
    }
});

function update_box_unit_condition(frm) {
    let conds = (frm.doc.item_unit_list || [])
        .map(r => r.unit_condition)
        .filter(Boolean);

    if (!conds.length) {
        frm.set_value('unit_condition', null);
        return;
    }

    let uniqueConds = [...new Set(conds)];
    let new_cond;

    if (uniqueConds.length === 1) {
        // All units have the same condition (e.g., all "OK")
        new_cond = uniqueConds[0];
    } else {
        // Mixed conditions found
        new_cond = 'Partially Ok';
    }

    if (frm.doc.unit_condition !== new_cond) {
        frm.set_value('unit_condition', new_cond);
    }
}

let scanTimer = null;

frappe.ui.form.on('Rental Item Unit', {
    refresh: function(frm) {
        // Automatically focus on the scan field
        frm.get_field('scan_serial').$input.focus();
    },

    scan_serial: function(frm) {
        clearTimeout(scanTimer);
        scanTimer = setTimeout(() => {
            if (frm.doc.scan_serial) {
                frm.events.call_unit_api(frm, frm.doc.scan_serial);
            }
        }, 300);
    },

    call_unit_api: function(frm, scan_value) {
        // Search across ID, Serial Number, and Unit Name fields
        frappe.db.get_list('Rental Item Unit', {
            filters: [
                ["name", "=", scan_value],
                ["or", ["unit_serial_number", "=", scan_value]],
                ["or", ["unit_name", "=", scan_value]]
            ],
            fields: ['name', 'unit_name', 'unit_condition', 'unit_serial_number', 'unit_type'],
            limit: 1
        }).then(res => {
            if (res && res.length > 0) {
                let d = res[0];
                
                // 1. TYPE VALIDATION: Prevent adding a Box inside another Box
                if (d.unit_type === "Box") {
                    frappe.msgprint({
                        title: __('Invalid Item'),
                        indicator: 'red',
                        message: __('Item <b>{0}</b> is a <b>Box</b>. A Box cannot be placed inside another Box.', [d.name])
                    });
                    frm.set_value('scan_serial', '');
                    return; // Stop the code here
                }

                // 2. SELF-REFERENCE VALIDATION: Prevent adding the box to itself
                if (d.name === frm.doc.name) {
                    frappe.msgprint(__('A box cannot contain itself.'));
                    frm.set_value('scan_serial', '');
                    return;
                }

                // 3. DUPLICATE CHECK
                let exists = (frm.doc.item_unit_list || []).some(row => row.document_id === d.name);
                if (exists) {
                    frappe.show_alert({message: __('Unit already in list'), indicator: 'orange'});
                } else {
                    // 4. ADD ROW AND POPULATE
                    let row = frm.add_child('item_unit_list');
                    
                    frappe.model.set_value(row.doctype, row.name, {
                        'document_id': d.name,
                        'unit_name': d.unit_name,
                        'unit_condition': d.unit_condition,
                        'unit_serial_number': d.unit_serial_number 
                    });

                    frm.refresh_field('item_unit_list');
                    frappe.show_alert({message: __('Unit Added'), indicator: 'green'});
                }
            } else {
                frappe.msgprint(__('ID <b>{0}</b> not found.', [scan_value]));
            }
            frm.set_value('scan_serial', '');
            frm.get_field('scan_serial').$input.focus();
        });
    }
});

// Logic for manual selection from the Document ID dropdown
frappe.ui.form.on('Box Item Unit Child Table', {
    document_id: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        if (row.document_id) {
            frappe.db.get_value('Rental Item Unit', row.document_id, 
                ['name', 'unit_name', 'unit_condition', 'unit_serial_number', 'unit_type'], 
                (d) => {
                    if (d) {
                        // TYPE VALIDATION for Manual Entry
                        if (d.unit_type === "Box") {
                            frappe.msgprint({
                                title: __('Invalid Item'),
                                indicator: 'red',
                                message: __('Item <b>{0}</b> is a <b>Box</b>. Only "Unit" types can be added.', [d.name])
                            });
                            // Remove the invalid row immediately
                            frm.get_field('item_unit_list').grid.grid_rows_by_docname[cdn].remove();
                            frm.refresh_field('item_unit_list');
                            return;
                        }

                        // POPULATE if it is a Unit
                        frappe.model.set_value(cdt, cdn, {
                            'unit_name': d.unit_name,
                            'unit_condition': d.unit_condition,
                            'unit_serial_number': d.unit_serial_number
                        });
                    }
                }
            );
        }
    }
});

// 1. Declare the timer once at the very top
let scanTimer = null;

frappe.ui.form.on('Rental Movement', {
    refresh: function(frm) {
        // Automatically focus on the scan field
        if (frm.get_field('scan_barcode')) {
            frm.get_field('scan_barcode').$input.focus();
        }
    },

    // Triggered when transaction type changes (e.g., from CHECK_OUT to CHECK_IN)
    transaction_type: function(frm) {
        const default_warehouse = "Main Warehouse";
        
        if (['CHECK_OUT', 'MAINTENANCE_OUT', 'LOST'].includes(frm.doc.transaction_type)) {
            frm.set_value('from_location', default_warehouse);
        } 
        else if (['CHECK_IN', 'MAINTENANCE_IN'].includes(frm.doc.transaction_type)) {
            frm.set_value('to_location', default_warehouse);
            frm.set_value('from_location', '');
        }
    },

    // 2. Handle Barcode Scanning
    scan_barcode: function(frm) {
        clearTimeout(scanTimer);
        scanTimer = setTimeout(() => {
            if (frm.doc.scan_barcode) {
                // Ensure To Location is set for Check Outs
                if (frm.doc.transaction_type === 'CHECK_OUT' && !frm.doc.to_location) {
                    frappe.msgprint(__('Please set the "To Location" before scanning.'));
                    frm.set_value('scan_barcode', '');
                    return;
                }
                frm.events.call_scan_api(frm, frm.doc.scan_barcode);
            }
        }, 300);
    },

    call_scan_api: function(frm, serial) {
        frappe.call({
            method: "handle_unit_scan", // Ensure this whitelist method exists in your .py file
            args: { serial: serial },
            callback: function(r) {
                if (r.message) {
                    let d = r.message;
                    
                    // Validate before adding
                    if (!validate_ui_logic(frm, d)) {
                        frm.set_value('scan_barcode', '');
                        return; 
                    }

                    // Add Child Row
                    let row = frm.add_child('rental_item_unit_child_table');
                    frappe.model.set_value(row.doctype, row.name, {
                        'unit_doc_id': d.name,
                        'unit_serial_number': d.unit_serial_number,
                        'unit_name': d.unit_name,
                        'unit_condition': d.unit_condition,
                        'prev_location': d.unit_location,
                        'prev_movement_status': d.movement_status
                    });

                    frm.refresh_field('rental_item_unit_child_table');
                    frappe.show_alert({message: __('Unit Added'), indicator: 'green'});
                }
                frm.set_value('scan_barcode', '');
                frm.get_field('scan_barcode').$input.focus();
            }
        });
    }
});

// 3. Table selection logic (Manual Row Entry)
frappe.ui.form.on('Rental Item Unit Child Table', {
    unit_doc_id: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        
        if (row.unit_doc_id) {
            frappe.db.get_value('Rental Item Unit', row.unit_doc_id, 
                ['name', 'unit_serial_number', 'unit_name', 'unit_condition', 'unit_location', 'movement_status'], 
                (d) => {
                    if (d) {
                        // Validate
                        if (!validate_ui_logic(frm, d)) {
                            frm.get_field('rental_item_unit_child_table').grid.grid_rows_by_docname[cdn].remove();
                            frm.refresh_field('rental_item_unit_child_table');
                            return;
                        }

                        // Populate if valid
                        frappe.model.set_value(cdt, cdn, {
                            'unit_serial_number': d.unit_serial_number,
                            'unit_name': d.unit_name,
                            'unit_condition': d.unit_condition,
                            'prev_location': d.unit_location,
                            'prev_movement_status': d.movement_status
                        });
                    }
                }
            );
        }
    }
});

/**
 * Shared Validation Logic
 */
function validate_ui_logic(frm, unit) {
    const tx = frm.doc.transaction_type;

    // A. Duplicate Check
    let existing_rows = (frm.doc.rental_item_unit_child_table || []).filter(row => row.unit_doc_id === unit.name);

    if (existing_rows.length > 1) {
        frappe.msgprint({
            title: __('Duplicate'),
            indicator: 'orange',
            message: `Unit <b>${unit.unit_serial_number}</b> is already in this list.`
        });
        return false;
    }
    
    // B. Check Out Rules
    if (tx === 'CHECK_OUT') {
        if (unit.movement_status !== 'Warehouse') {
            frappe.msgprint({
                title: __('Invalid Status'),
                indicator: 'red',
                message: `Unit <b>${unit.unit_serial_number}</b> is currently <b>${unit.movement_status}</b>. It must be in 'Warehouse' to Check Out.`
            });
            return false;
        }
        if (unit.unit_condition !== 'OK') {
            frappe.msgprint({
                title: __('Condition Issue'),
                indicator: 'orange',
                message: `Unit <b>${unit.unit_serial_number}</b> is <b>${unit.unit_condition}</b>. Only 'OK' units can be Checked Out.`
            });
            return false;
        }
    }

    // C. Maintenance In Rules
    if (tx === 'MAINTENANCE_IN' && unit.movement_status !== 'In Maintenance') {
        frappe.msgprint({
            title: __('Status Mismatch'),
            indicator: 'red',
            message: `Unit <b>${unit.unit_serial_number}</b> is not currently marked as 'In Maintenance'.`
        });
        return false;
    }

    return true;
}

frappe.ui.form.on('Rental Item Template', {
    onload: function(frm) {
        // Show item_name and make read-only
        frm.toggle_display('item_name', true);
        frm.set_df_property('item_name', 'read_only', 1); // read-only
        if (!frm.doc.item_name) {
            frm.set_value('item_name', '-');
        }

        // Show sku_naming_series and make read-only
        frm.toggle_display('sku_naming_series', true);
        frm.set_df_property('sku_naming_series', 'read_only', 1); // read-only
        if (!frm.doc.sku_naming_series) {
            frm.set_value('sku_naming_series', '-');
        }
    },

    item_model: function(frm) { 
        generate_sku(frm); 
    },
    item_brand: function(frm) { 
        generate_sku(frm); 
    },
    item_type: function(frm) { 
        generate_sku(frm); 
    },
    rental_item_type_box: function(frm) { 
        generate_sku(frm); 
    }, 
    suffix: function(frm) { 
        generate_sku(frm); 
    },
});

function generate_sku(frm) {
    const full_code = (val) => (val || "").replace(/[^a-zA-Z0-9]/g, "").toUpperCase();
    const short_code = (val) => full_code(val).substring(0, 2);

    let model_full = full_code(frm.doc.item_model);
    let brand_short = short_code(frm.doc.item_brand);
    let type_short = short_code(frm.doc.item_type);
    let item_kind = frm.doc.rental_item_type_box;

    let suffix_digits = parseInt(frm.doc.suffix);

    if (!model_full || !suffix_digits) {
        frm.set_value('sku_naming_series', '-'); // default if incomplete
        return;
    }

    let prefix = item_kind === "Box" ? model_full : `${model_full}-${brand_short}-${type_short}`;
    let sequence_mask = '#'.repeat(suffix_digits);

    frm.set_value('sku_naming_series', `${prefix}-${sequence_mask}`);
}

frappe.listview_settings["Rental Item Maintenance"] = {
    formatters: {
        workflow_state(value, df, doc) {
            if (value === "Attention Required") {
                return `<span style="color:#d92d20;font-weight:600;">${value}</span>`;
            }
            if (value === "In Repair") {
                return `<span style="color:#f79009;font-weight:600;">${value}</span>`;
            }
            if (value === "Complete") {
                return `<span style="color:#12b76a;font-weight:600;">${value}</span>`;
            }
            return value;
        },

        reported_condition(value) {
            if (value === "Damaged") {
                return `<span style="color:#d92d20;font-weight:600;">${value}</span>`;
            }
            if (value === "Need Cleaning") {
                return `<span style="color:#2563eb;font-weight:600;">${value}</span>`;
            }
            return value;
        }
    }
};

frappe.listview_settings['Rental Item Unit'] = {
    get_indicator: function(doc) {
        if (!doc.cond) return;
        
        // Map your field values to colors
        const map = {
            'OK': ['OK', 'green'],
            'Needs Cleaning': ['Needs Cleaning', 'blue'],
            'Under Repair': ['Under Repair', 'orange'],
            'Defective': ['Defective', 'red'],
            'Partially OK': ['Partially OK', 'purple']
        };

        return map[doc.cond] || ['Unknown', 'gray'];
    }
};

frappe.listview_settings['Rental Item Unit'] = {
    formatters: {
        current_condition: function(value, df, doc) {
            let bg_color = "";
            let text_color = "#ffffff"; // White text for better contrast on dark pills

            switch(value) {
                case "OK":
                    bg_color = "#28a745"; // Success Green
                    break;
                case "Partially Ok":
                case "Needs Cleaning":
                    bg_color = "#ffc107"; // Warning Yellow
                    text_color = "#000000"; // Black text for yellow background
                    break;
                case "Damaged":
                    bg_color = "#dc3545"; // Danger Red
                    break;
                case "Scrapped":
                    bg_color = "#6c757d"; // Secondary Gray
                    break;
                default:
                    return value;
            }

            return `
                <span class="pill" style="
                    background-color: ${bg_color};
                    color: ${text_color};
                    padding: 4px 12px;
                    border-radius: 20px;
                    font-size: 11px;
                    font-weight: 500;
                    display: inline-block;
                    text-align: center;
                    min-width: 80px;
                ">
                    ${__(value)}
                </span>
            `;
        }
    }
};

frappe.ui.form.on('Rental Item Maintenance', {
    onload: function(frm) {
        // Set placeholders on a new document
        if (frm.is_new()) {
            reset_unit_fields(frm);
        }
    },

    scan_barcode: function(frm) {
        if (!frm.doc.scan_barcode) return;

        frappe.call({
            method: "get_rental_unit_by_serial",
            args: {
                serial_number: frm.doc.scan_barcode.trim()
            },
            callback: function(r) {
                if (r.message) {
                    const unit = r.message;
                    frm.set_value('unit_serial_number', unit.name); 
                    frm.set_value('serial_number', unit.unit_serial_number);
                    frm.set_value('unit_name', unit.unit_name);
                    
                    frappe.show_alert({message: __("Unit Linked"), indicator: 'green'});
                } else {
                    // Reset to placeholder if scan fails or is invalid
                    reset_unit_fields(frm);
                }
                
                frm.set_value('scan_barcode', '');
                setTimeout(() => frm.get_field('scan_barcode').$input.focus(), 100);
            }
        });
    }
});

// Helper function to keep code clean
function reset_unit_fields(frm) {
    frm.set_value('unit_name', '-');
    frm.set_value('serial_number', '-');
    // Note: Don't set the Link field (unit_serial_number) to '-' 
    // because it will throw a validation error. Keep it empty or 
    // handle it as a data field if it's just for display.
}

frappe.ui.form.on('Rental Item Unit', {
    refresh: function(frm) {
        // Force fetch latest values from DB to ensure they aren't empty
        frappe.db.get_doc(frm.doctype, frm.docname).then(doc => {
            //frm.dashboard.clear_headline();
            
            if (doc.movement_status) frm.dashboard.add_indicator(__(doc.movement_status), "blue");
            if (doc.unit_location) frm.dashboard.add_indicator(__(doc.unit_location), "blue");
            if (doc.unit_condition) frm.dashboard.add_indicator(__(doc.unit_condition), "blue");
            if (doc.maintenance_status) frm.dashboard.add_indicator(__(doc.maintenance_status), "blue");
        });
        frm.dashboard.add_comment("Announcement", "alert-info", false);
    }
    
});

frappe.ui.form.on("Rental Item Maintenance", {

    workflow_state(frm) {
        frm.trigger("sync_unit_maintenance_status");
        frm.trigger("update_fields_ui");
    },

    after_save(frm) {
        frm.trigger("sync_unit_maintenance_status");
    },

    sync_unit_maintenance_status(frm) {
        if (!frm.doc.rental_item_unit || !frm.doc.workflow_state) return;

        frappe.call({
            method: "frappe.client.set_value",
            args: {
                doctype: "Rental Item Unit",
                name: frm.doc.rental_item_unit,
                fieldname: "maintenance_status",
                value: frm.doc.workflow_state
            },
            freeze: false
        });
    }

});

frappe.ui.form.on('Rental Item Template', {
    sku_naming_series(frm) {
        const sku = frm.doc.sku_naming_series || "";
        const length = sku.length;

        frm.set_value('sku_character_count', length);

        if (frm.doc.item_type === "Unit" && length > 15) {
            frappe.msgprint({
                title: "SKU Too Long",
